func (a *adapter) MyMethod(ctx context.Context, params plan.MyInput) (*plan.Plan, error) {
	fn := func(ctx context.Context, a *adapter) (*plan.Plan, error) {
		if err := params.Validate(); err != nil {
			return nil, fmt.Errorf("invalid params: %w", err)
		}
		row, err := a.db.Plan.Query().
			Where(plandb.Namespace(params.Namespace), plandb.ID(params.ID)).
			WithPhases(planPhaseIncludeDeleted(false), planPhaseEagerLoadRateCardsFn).
			First(ctx)
		if err != nil {
			if entdb.IsNotFound(err) {
				return nil, plan.NewNotFoundError(plan.NotFoundErrorParams{Namespace: params.Namespace, ID: params.ID})
			}
			return nil, fmt.Errorf("failed to get Plan: %w", err)
		}
		return FromPlanRow(*row)
	}
	return entutils.TransactingRepo[*plan.Plan, *adapter](ctx, a, fn)
}

type (
	MyPlanRequest  = plan.MyPlanInput
	MyPlanResponse = api.Plan
	MyPlanHandler  httptransport.HandlerWithArgs[MyPlanRequest, MyPlanResponse, string]
)

func (h *handler) MyPlan() MyPlanHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, planID string) (MyPlanRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return MyPlanRequest{}, fmt.Errorf("failed to resolve namespace: %w", err)
			}
			return MyPlanRequest{NamespacedID: models.NamespacedID{Namespace: ns, ID: planID}}, nil
		},
		func(ctx context.Context, request MyPlanRequest) (MyPlanResponse, error) {
			p, err := h.service.MyPlan(ctx, request)
			if err != nil {
				return MyPlanResponse{}, fmt.Errorf("failed to my-plan: %w", err)
			}
			return FromPlan(*p)
		},
		commonhttp.JSONResponseEncoderWithStatus[MyPlanResponse](http.StatusOK),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("myPlan"),
			httptransport.WithErrorEncoder(productcataloghttp.ValidationErrorEncoder(productcataloghttp.ResourceKindPlan)),
		)...,
	)
}

func (s service) MyMutation(ctx context.Context, params plan.MyInput) (*plan.Plan, error) {
	fn := func(ctx context.Context) (*plan.Plan, error) {
		if err := params.Validate(); err != nil {
			return nil, fmt.Errorf("invalid params: %w", err)
		}
		p, err := s.adapter.GetPlan(ctx, plan.GetPlanInput{NamespacedID: params.NamespacedID})
		if err != nil {
			return nil, fmt.Errorf("failed to get Plan: %w", err)
		}
		if !lo.Contains([]productcatalog.PlanStatus{productcatalog.PlanStatusDraft}, p.Status()) {
			return nil, models.NewGenericValidationError(fmt.Errorf("plan must be in draft status"))
		}
		p, err = s.adapter.UpdatePlan(ctx, plan.UpdatePlanInput{NamespacedID: params.NamespacedID})
		if err != nil {
			return nil, fmt.Errorf("failed to update Plan: %w", err)
		}
		event := plan.NewPlanUpdateEvent(ctx, p)
		if err := s.publisher.Publish(ctx, event); err != nil {
			return nil, fmt.Errorf("failed to publish plan updated event: %w", err)
		}
		return p, nil
	}
	return transaction.Run(ctx, s.adapter, fn)
}
